import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

/**
 * Tests for spacing around colon in annotations, verifying the fix for issue #2093.
 * https://github.com/pinterest/ktlint/issues/2093
 */
class SpacingAroundColonInAnnotationRuleTest {
    private val spacingAroundColonRuleAssertThat = assertThatRule { SpacingAroundColonRule() }

    @Nested
    inner class `Given annotation with use-site target` {
        @Test
        fun `Given a file annotation with no spacing around colon then no violation is reported`() {
            val code =
                """
                @file:JvmName("Foo")
                """.trimIndent()
            spacingAroundColonRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a file annotation with space before colon then report violation`() {
            val code =
                """
                @file :JvmName("Foo")
                """.trimIndent()
            val formattedCode =
                """
                @file:JvmName("Foo")
                """.trimIndent()
            spacingAroundColonRuleAssertThat(code)
                .hasLintViolation(1, 6, "Unexpected spacing before \":\"")
                .isFormattedAs(formattedCode)
        }

        @Test
        fun `Given a file annotation with space after colon then report violation`() {
            val code =
                """
                @file: JvmName("Foo")
                """.trimIndent()
            val formattedCode =
                """
                @file:JvmName("Foo")
                """.trimIndent()
            spacingAroundColonRuleAssertThat(code)
                .hasLintViolation(1, 7, "Unexpected spacing after \":\"")
                .isFormattedAs(formattedCode)
        }

        @Test
        fun `Given a file annotation with space around colon then report violation`() {
            val code =
                """
                @file : JvmName("Foo")
                """.trimIndent()
            val formattedCode =
                """
                @file:JvmName("Foo")
                """.trimIndent()
            spacingAroundColonRuleAssertThat(code)
                .hasLintViolation(1, 6, "Unexpected spacing around \":\"")
                .isFormattedAs(formattedCode)
        }
    }

    @Nested
    inner class `Given annotation entry with use-site target` {
        @Test
        fun `Given a set annotation entry with no spacing around colon then no violation is reported`() {
            val code =
                """
                class Example {
                    @set:[Inject VisibleForTesting]
                    public var collaborator: Collaborator
                }
                """.trimIndent()
            spacingAroundColonRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a set annotation entry with space before colon then report violation`() {
            val code =
                """
                class Example {
                    @set :[Inject VisibleForTesting]
                    public var collaborator: Collaborator
                }
                """.trimIndent()
            val formattedCode =
                """
                class Example {
                    @set:[Inject VisibleForTesting]
                    public var collaborator: Collaborator
                }
                """.trimIndent()
            spacingAroundColonRuleAssertThat(code)
                .hasLintViolation(2, 9, "Unexpected spacing before \":\"")
                .isFormattedAs(formattedCode)
        }

