    @Nested
    inner class `Given annotation with use-site target` {
        @Test
        fun `Given a file annotation with no spacing around colon then no violation is reported`() {
            val code =
                """
                @file:JvmName("Foo")
                """.trimIndent()
            spacingAroundColonRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a file annotation with space before colon then report violation`() {
            val code =
                """
                @file :JvmName("Foo")
                """.trimIndent()
